import{_ as i,c as s,a,o as l}from"./app-CEcM0piI.js";const r={};function t(n,e){return l(),s("div",null,e[0]||(e[0]=[a(`<p>在浏览器中创建一个线程执行指定的js代码逻辑</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>new Worker(path)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>传入的js文件路径需要是线上的地址，线下的地址无法执行 通常是放在静态资源目录中</p><p><strong>缺点</strong></p><ol><li>webworker不能使用本地文件，必须是网上的<strong>同源文件</strong>（其他源的不行）</li><li>webworker不能使用window上的dom操作，也不能获取dom对象，dom相关的东西只有主线程有。只能做一些计算相关的操作</li><li>有的东西是无法通过主线程传递个子线程的，比如方法，dom节点，一些对象里的特殊设置（freeze，getter，setter这些，所以 vue的响应式对象是不能传递的)</li><li>模块的引入问题</li></ol><p>当前创建worker对象的线程为主线程，worker执行的任务为子线程，子线程和主线程执行是可以通信的</p><p>在子线程中有一个self对象，它和this类似，但它的指向永远不会改变，指向的都是本子线程</p><ol><li>主线程创建Worker并监听消息</li></ol><div class="language-主线程 line-numbers-mode" data-highlighter="shiki" data-ext="主线程" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>let worker=new Worker(&#39;http://localhost:3000/assets/worker&#39;)</span></span>
<span class="line"><span>worker.addEventListener(&#39;message&#39;,(e)=&gt;{</span></span>
<span class="line"><span>	console.log(e)</span></span>
<span class="line"><span>})</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ol start="2"><li>子线程发送消息</li></ol><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>self.postMessage(2)</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><blockquote><p>[!NOTE] Title</p><ol><li>子线程和主线程都可以监听和发送消息</li><li>发送消息只能发送基本数据类型</li><li>要引入模块需要使用impoertScripts()函数，传入的地址是线上的js文件地址，这个文件可以不是同源文件（为了能够使用其他的库）</li><li>如果要执行的子线程文件使用了es6的默认导出，需要在创建worker时添加额外的type参数知名module</li></ol></blockquote><h3 id="应用" tabindex="-1"><a class="header-anchor" href="#应用"><span>应用</span></a></h3><p>因为webworker的限制，就别想着多线程渲染dom了。因为他根本无法创建dom，所以vue和 react框架没有考虑webworker，webworker的常见主要就是耗时的计算</p><ol><li>随着webgl，canvas等能力的加入，web前端有越来越多的可视化操作。比如在线滤镜，在线绘图，web游戏等等。这些东西都是非常消耗计算的</li><li>一些后台管理系统也会涉及到一些，最常见的就是一些电子表单。大量的数据大量的计算，比如10万条数据导出为excel表格</li></ol>`,15)]))}const d=i(r,[["render",t]]),p=JSON.parse('{"path":"/front/js/6/","title":"6 WebWorker","lang":"zh-CN","frontmatter":{"title":"6 WebWorker","createTime":"2025/06/18 21:11:40","permalink":"/front/js/6/"},"readingTime":{"minutes":2,"words":601},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/前端/JavaScript/6 WebWorker.md","headers":[]}');export{d as comp,p as data};
